let isOnline=navigator.onLine;let serviceWorkerRegistration=null;document.addEventListener('DOMContentLoaded',function(){initializeApp();});function initializeApp(){if('serviceWorker'in navigator){registerServiceWorker();}window.addEventListener('online',handleOnline);window.addEventListener('offline',handleOffline);setupGlobalFormHandling();setupSearchFunctionality();updateOfflineIndicator();}async function registerServiceWorker(){try{serviceWorkerRegistration=await navigator.serviceWorker.register('/static/js/sw.js');console.log('Service Worker registered successfully');}catch(error){console.error('Service Worker registration failed:',error);}}function handleOnline(){isOnline=true;updateOfflineIndicator();syncOfflineData();}function handleOffline(){isOnline=false;updateOfflineIndicator();}function updateOfflineIndicator(){let indicator=document.getElementById('offline-indicator');if(!isOnline){if(!indicator){indicator=document.createElement('div');indicator.id='offline-indicator';indicator.className='offline-indicator';indicator.innerHTML='📡 You are offline. Some features may be limited.';document.body.appendChild(indicator);}}else{if(indicator){indicator.remove();}}}async function syncOfflineData(){const offlineData=getOfflineData();if(offlineData.length>0){console.log('Syncing offline data...');for(const data of offlineData){try{await fetch(data.url,{method:data.method,headers:data.headers,body:data.body});removeOfflineData(data.id);}catch(error){console.error('Failed to sync offline data:',error);}}}}function getOfflineData(){const data=localStorage.getItem('offlineData');return data?JSON.parse(data):[];}function storeOfflineData(id,url,method,headers,body){const offlineData=getOfflineData();offlineData.push({id,url,method,headers,body,timestamp:Date.now()});localStorage.setItem('offlineData',JSON.stringify(offlineData));}function removeOfflineData(id){const offlineData=getOfflineData();const filtered=offlineData.filter(item=>item.id!==id);localStorage.setItem('offlineData',JSON.stringify(filtered));}function setupGlobalFormHandling(){document.addEventListener('submit',function(e){const form=e.target;if(form.hasAttribute('data-ajax')){e.preventDefault();handleAjaxForm(form);}});}async function handleAjaxForm(form){const formData=new FormData(form);const url=form.action||window.location.href;const method=form.method||'POST';try{const response=await fetch(url,{method:method,body:formData});if(response.ok){const data=await response.json();handleFormSuccess(form,data);}else{throw new Error('Form submission failed');}}catch(error){handleFormError(form,error);}}function handleFormSuccess(form,data){showNotification('Success!','success');if(form.hasAttribute('data-reset')){form.reset();}if(data.redirect){window.location.href=data.redirect;}}function handleFormError(form,error){console.error('Form error:',error);showNotification('Something went wrong. Please try again.','error');}function setupSearchFunctionality(){const searchForm=document.getElementById('festival-search-form');if(searchForm){searchForm.addEventListener('submit',handleSearch);}const searchInput=document.getElementById('festival-search');if(searchInput){let searchTimeout;searchInput.addEventListener('input',function(){clearTimeout(searchTimeout);searchTimeout=setTimeout(()=>{showSearchSuggestions(this.value);},300);});}}async function handleSearch(e){e.preventDefault();const searchInput=document.getElementById('festival-search');const query=searchInput.value.trim();if(!query)return;const searchType=searchInput.placeholder.includes('artist')?'artists':'festivals';window.location.href=`/search?q=${encodeURIComponent(query)}&type=${searchType}`;}async function showSearchSuggestions(query){if(!query||query.length<2){hideSearchSuggestions();return;}try{const response=await fetch(`/api/v1/search/suggestions?q=${encodeURIComponent(query)}`);if(response.ok){const data=await response.json();displaySearchSuggestions(data.suggestions);}}catch(error){console.error('Error fetching search suggestions:',error);}}function displaySearchSuggestions(suggestions){let suggestionsContainer=document.getElementById('search-suggestions');if(!suggestionsContainer){suggestionsContainer=document.createElement('div');suggestionsContainer.id='search-suggestions';suggestionsContainer.className='search-suggestions';const searchInput=document.getElementById('festival-search');searchInput.parentNode.appendChild(suggestionsContainer);}if(suggestions.length===0){hideSearchSuggestions();return;}suggestionsContainer.innerHTML=suggestions.map(suggestion=>`<div class="suggestion-item"onclick="selectSuggestion('${suggestion.text}', '${suggestion.type}')"><span class="suggestion-icon">${suggestion.type==='festival'?'🎪':'🎤'}</span><span class="suggestion-text">${suggestion.text}</span><span class="suggestion-type">${suggestion.type}</span></div>`).join('');suggestionsContainer.style.display='block';}function hideSearchSuggestions(){const suggestionsContainer=document.getElementById('search-suggestions');if(suggestionsContainer){suggestionsContainer.style.display='none';}}function selectSuggestion(text,type){const searchInput=document.getElementById('festival-search');searchInput.value=text;hideSearchSuggestions();const searchForm=document.getElementById('festival-search-form');if(searchForm){searchForm.dispatchEvent(new Event('submit'));}}function showNotification(message,type='info'){const notification=document.createElement('div');notification.className=`notification notification-${type}`;notification.textContent=message;document.body.appendChild(notification);setTimeout(()=>{notification.classList.add('show');},100);setTimeout(()=>{notification.classList.remove('show');setTimeout(()=>{notification.remove();},300);},3000);}function formatDate(dateString){const date=new Date(dateString);return date.toLocaleDateString('en-US',{year:'numeric',month:'short',day:'numeric'});}function formatDateRange(dates){if(!dates||dates.length===0)return'Dates TBA';if(dates.length===1){return formatDate(dates[0]);}const startDate=new Date(dates[0]);const endDate=new Date(dates[dates.length-1]);if(startDate.getFullYear()===endDate.getFullYear()&&startDate.getMonth()===endDate.getMonth()){return`${startDate.toLocaleDateString('en-US',{month:'short',day:'numeric'})}-${endDate.toLocaleDateString('en-US',{day:'numeric',year:'numeric'})}`;}else{return`${formatDate(dates[0])}-${formatDate(dates[dates.length-1])}`;}}function truncateText(text,maxLength){if(text.length<=maxLength)return text;return text.substring(0,maxLength)+'...';}window.FestivalPlaylistApp={showNotification,formatDate,formatDateRange,truncateText,isOnline:()=>isOnline};